import React, { useState } from 'react';
import axios from 'axios';
import MapDisplay from './components/MapDisplay';
import SafetyIndicators from './components/SafetyIndicators';
import SOSButton from './components/SOSButton';
import './App.css';
import { MapPinIcon, MagnifyingGlassIcon } from '@heroicons/react/24/solid';

function App() {
  const [source, setSource] = useState('');
  const [destination, setDestination] = useState('');
  const [sourceCoords, setSourceCoords] = useState(null);
  const [destinationCoords, setDestinationCoords] = useState(null);
  const [routeFound, setRouteFound] = useState(false);
  const [loading, setLoading] = useState(false);
  const [safeWaypoints, setSafeWaypoints] = useState([]);

  const geocode = async (place) => {
    try {
      const res = await axios.get(`https://nominatim.openstreetmap.org/search`, {
        params: { q: place, format: 'json', limit: 1 },
      });
      if (res.data.length > 0) {
        return { lat: parseFloat(res.data[0].lat), lng: parseFloat(res.data[0].lon) };
      }
    } catch (err) { console.error(err); }
    return null;
  };

  const handleFindRoute = async () => {
    if (!source.trim() || !destination.trim()) return alert('Enter locations');
    setLoading(true);
    try {
      const src = await geocode(source);
      const dest = await geocode(destination);
      if (!src || !dest) return alert('Location not found');
      
      setSourceCoords(src);
      setDestinationCoords(dest);

      const response = await axios.post('http://localhost:3002/getSafeRoute', { source: src, destination: dest });
      setSafeWaypoints(response.data.waypoints || [src, dest]);
      setRouteFound(true);
    } catch (error) {
      alert("Check if backend is on 3002");
    } finally { setLoading(false); }
  };

  return (
    <div className="relative h-screen w-full bg-gray-900 font-sans overflow-hidden">
      
      {/* Background Layer: Map */}
      <div className="absolute inset-0 z-0">
         <MapDisplay waypoints={safeWaypoints} source={sourceCoords} destination={destinationCoords} /> 
      </div>

      {/* Foreground Layer: Minimalist UI Card */}
      <div className="absolute top-6 left-6 z-20 w-80">
        <div className="bg-white/90 backdrop-blur-lg shadow-2xl rounded-2xl p-5 border border-white/20">
          
          {/* Header */}
          <div className="flex items-center space-x-3 mb-5">
            <img 
              src={process.env.PUBLIC_URL + '/Logo.jpeg'} 
              alt="Logo" 
              className="h-10 w-10 rounded-full object-cover shadow-sm ring-2 ring-purple-500/20"
              onError={(e) => e.target.src = 'https://ui-avatars.com/api/?name=S&background=7c3aed&color=fff'}
            />
            <div>
              <h1 className="text-xl font-black text-gray-900 tracking-tight leading-none">SheRoute</h1>
              <p className="text-[10px] font-bold text-purple-600 uppercase tracking-widest mt-1">Navigate Safely</p>
            </div>
          </div>
          
          {/* Form */}
          <div className="space-y-3">
            <div className="relative">
              <MapPinIcon className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-gray-400" />
              <input
                type="text"
                placeholder="Start point..."
                value={source}
                onChange={(e) => setSource(e.target.value)}
                className="w-full pl-9 pr-3 py-2.5 bg-gray-100/50 border-none rounded-xl text-xs font-semibold focus:ring-2 focus:ring-purple-500 transition-all"
              />
            </div>

            <div className="relative">
              <MapPinIcon className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-pink-500" />
              <input
                type="text"
                placeholder="Destination..."
                value={destination}
                onChange={(e) => setDestination(e.target.value)}
                className="w-full pl-9 pr-3 py-2.5 bg-gray-100/50 border-none rounded-xl text-xs font-semibold focus:ring-2 focus:ring-pink-500 transition-all"
              />
            </div>

            <button
              onClick={handleFindRoute}
              disabled={loading}
              className="w-full flex items-center justify-center space-x-2 bg-gray-900 hover:bg-black text-white py-3 rounded-xl shadow-lg transition-transform active:scale-95 disabled:opacity-50"
            >
              <MagnifyingGlassIcon className={`h-4 w-4 ${loading ? 'animate-spin' : ''}`} />
              <span className="text-xs font-bold uppercase tracking-wider">
                {loading ? 'Analyzing...' : 'Find Safe Route'}
              </span>
            </button>
          </div>

          {routeFound && (
            <div className="mt-4 pt-4 border-t border-gray-100">
               <SafetyIndicators />
            </div>
          )}
        </div>
      </div>

      <SOSButton />
    </div>
  );
}

export default App;
